function placeholderImage(seed = 'item') { const text = encodeURIComponent(String(seed).slice(0, 24) || 'item'); return `https://via.placeholder.com/640x640/111827/f3d88b?text=${text}`; }
function formatDateTime(value) { if (!value) return ''; const d = new Date(value); if (Number.isNaN(d.getTime())) return String(value); return new Intl.DateTimeFormat('ar-EG', { dateStyle: 'medium', timeStyle: 'short' }).format(d); }
function countdownTo(value) { if (!value) return ''; const d = new Date(value); if (Number.isNaN(d.getTime())) return ''; const diff = Math.max(0, d.getTime() - Date.now()); const minutes = Math.floor(diff / 60000); const hours = Math.floor(minutes / 60); const days = Math.floor(hours / 24); const hh = String(hours % 24).padStart(2, '0'); const mm = String(minutes % 60).padStart(2, '0'); if (days > 0) return `${days}ي ${hh}س ${mm}د`; if (hours > 0) return `${hours}س ${mm}د`; return `${Math.max(0, minutes)}د`; }
