function showToast(message, type = 'info') { if (!els.toast) return; const text = String(message ?? '').trim(); if (!text) return; els.toast.classList.remove('hidden'); els.toast.textContent = text; els.toast.dataset.type = type; clearTimeout(showToast.timer); showToast.timer = setTimeout(() => { els.toast.classList.add('hidden'); els.toast.textContent = ''; }, type === 'error' ? 5000 : 3200); }
function closeOverlay(el) { if (!el) return; el.classList.add('hidden'); el.setAttribute('aria-hidden', 'true'); }
