function parseHash() { const raw = currentHash(); const parts = raw.split('/').filter(Boolean); if (!parts.length || parts[0] === 'home') return { type: 'home' }; if (parts[0] === 'company' && parts[1]) return { type: 'company', companyId: parts[1] }; if (parts[0] === 'tiers') return { type: 'tiers' }; if (parts[0] === 'deals') return { type: 'deals' }; if (parts[0] === 'flash') return { type: 'flash' }; if (parts[0] === 'cart') return { type: 'cart' }; if (parts[0] === 'account') return { type: 'account' }; if (parts[0] === 'register') return { type: 'register' }; return { type: 'home' }; }
