function appBannerImage() { return pickSetting(['banner_image', 'home_banner_image', 'banner', 'hero_banner', 'main_banner']); }
function companyBannerHtml() { const image = appBannerImage(); if (image) return `<section class="company-banner-surface" aria-label="بانر الشركة"><img class="company-banner-image" src="${escapeHtml(image)}" alt="بانر الشركة" loading="eager" /></section>`; const company = escapeHtml(settingValue('company_name', 'الأهرام للتجارة والتوزيع')); const subtitle = escapeHtml(settingValue('banner_subtitle', 'Commerce first')); return `<section class="company-banner-surface company-banner-fallback" aria-label="بانر الشركة"><div class="company-banner-fallback-copy"><span class="company-banner-kicker">Branding only</span><strong>${company}</strong><small>${subtitle}</small></div></section>`; }
