function getFlashState() { const offer = state.flashOffers[0] || null; const active = activeFlashOffer(); const current = active || offer; if (!current) return { offer: null, status: null, remaining: '', endedAt: '' }; if (current.status === 'active' || current.can_buy) return { offer: current, status: 'active', remaining: countdownTo(current.end_time), endedAt: formatDateTime(current.end_time) }; if (current.status === 'expired') return { offer: current, status: 'expired', remaining: '', endedAt: formatDateTime(current.end_time) }; return { offer: current, status: 'pending', remaining: countdownTo(current.start_time), endedAt: formatDateTime(current.start_time) }; }
function getSelectedTierObject() { if (!state.selectedTier) return null; if (typeof state.selectedTier === 'string') return state.tiers.find((tier) => tier.tier_name === state.selectedTier) || { tier_name: state.selectedTier }; return state.selectedTier; }
function tierDisplayLabel(tier) { const raw = String(tier?.visible_label || tier?.tier_name || 'الشريحة الرئيسية').trim(); if (!raw) return 'الشريحة الرئيسية'; return raw.toLowerCase() === 'base' ? 'الشريحة الرئيسية' : raw; }
function getSelectedTierLabel() { const tier = getSelectedTierObject(); return tier ? tierDisplayLabel(tier) : 'الشريحة الرئيسية'; }
function selectedTierMinimum() { const tier = getSelectedTierObject(); return Number(tier?.min_order || 0); }
