function tierStatusLine() { const tier = getSelectedTierObject(); if (!tier) return 'اختر شريحة تجارية لبدء التسعير'; const remaining = tierRemainingAmount() || 0; if (remaining > 0) return `متبقي ${num(remaining)} ج.م للوصول إلى ${num(selectedTierMinimum())}`; return 'مؤهل بالكامل ضمن هذه الشريحة'; }
function availableUnits(product) { const units = []; if (product.has_carton || Number(product.carton_price) > 0) units.push('carton'); if (product.has_pack || Number(product.pack_price) > 0) units.push('pack'); return units; }
function currentUnitForProduct(product) { const saved = state.unitPrefs?.[product.product_id]; const available = availableUnits(product); if (saved && available.includes(saved)) return saved; if (available.includes('carton')) return 'carton'; if (available.includes('pack')) return 'pack'; return 'carton'; }
function baseUnitPrice(product, unit) { return unit === 'pack' ? Number(product.pack_price || 0) : Number(product.carton_price || 0); }
function resolveProductPrice(product, unit) { const tier = getSelectedTierObject(); const tierName = tier?.tier_name || null; const productId = String(product?.product_id || '').trim(); const key = tierName ? `${tierName}::${productId}` : ''; const isPackUnit = String(unit || '') === 'pack'; if (tierName && key) { const tierMap = isPackUnit ? state.tierPrices.pack : state.tierPrices.carton; const tierMapped = tierMap.get(key); if (Number.isFinite(Number(tierMapped)) && Number(tierMapped) > 0) return Number(tierMapped); } if (isPackUnit && product?.discount_pack === false) return baseUnitPrice(product, unit); if (!isPackUnit && product?.discount_carton === false) return baseUnitPrice(product, unit); const base = baseUnitPrice(product, unit); const discount = tier && product.allow_discount !== false ? Number(tier.discount_percent || 0) : 0; if (discount > 0 && base > 0) return Number((base * (1 - discount / 100)).toFixed(2)); return base; }
function displayPriceText(product, unit) { const price = resolveProductPrice(product, unit); if (!price) return '—'; return `${num(price)} ج.م`; }
function companyName(companyId) { return state.companyMap.get(String(companyId))?.company_name || String(companyId || ''); }
function compareNatural(a, b) { return String(a ?? '').localeCompare(String(b ?? ''), 'ar', { numeric: true, sensitivity: 'base' }); }
function sortCompanies(rows = []) { return [...rows].sort((a, b) => compareNatural(a.company_name, b.company_name)); }
function sortProducts(rows = []) { return [...rows].sort((a, b) => compareNatural(a.product_name, b.product_name)); }
function filteredCompanies() { const q = normalizeText(state.search); const rows = state.companies.filter((company) => { if (state.companyFilter && String(company.company_id) !== String(state.companyFilter)) return false; if (!q) return true; return normalizeText(company.company_name).includes(q) || normalizeText(company.company_id).includes(q); }); return sortCompanies(rows); }
function normalizeProductRow(row, cartonPrice = null, packPrice = null) { const productId = String(row.product_id ?? row.id ?? '').trim(); const derivedCarton = Number(row.carton_price ?? row.price ?? cartonPrice ?? 0); const derivedPack = Number(row.pack_price ?? packPrice ?? 0); return { ...row, product_id: productId, product_name: row.product_name || row.name || '', company_id: String(row.company_id || ''), product_image: row.product_image || row.image || '', status: row.status || 'active', visible: row.visible !== false, has_carton: row.has_carton ?? derivedCarton > 0, has_pack: row.has_pack ?? derivedPack > 0, carton_price: derivedCarton, pack_price: derivedPack, allow_discount: row.allow_discount ?? true, discount_carton: row.discount_carton ?? true, discount_pack: row.discount_pack ?? true }; }
function normalizeDeals(rows = []) { return rows.map((row, index) => ({ ...row, id: String(row.id ?? row.deal_id ?? index), title: row.title || row.deal_title || row.name || 'عرض خاص', description: row.description || row.deal_description || '', image: row.image || row.deal_image || '', price: Number(row.price ?? row.sale_price ?? row.amount ?? 0), discount_percent: Number(row.discount_percent ?? row.discount_rate ?? 0), status: row.status || 'active' })).filter((row) => row.title); }
