function renderCompanies() { const rows = filteredCompanies(); const cards = rows.slice(0, 12).map((company) => `<article class="company-card company-card-home"><button type="button" class="company-btn" data-action="open-company" data-company-id="${escapeHtml(company.company_id)}"><img class="company-logo" src="${escapeHtml(company.company_logo || placeholderImage(company.company_name))}" alt="${escapeHtml(company.company_name)}" loading="lazy" /><div class="company-name">${escapeHtml(company.company_name)}</div></button></article>`).join(''); setHtml(els.companiesSurface, `<section class="section-card company-shelf"><div class="section-head"><div><h2>الشركات</h2><div class="helper-text">اضغط على شركة لعرض منتجاتها فقط.</div></div><button class="ghost-btn" type="button" data-action="clear-company-filter">إظهار الكل</button></div><div class="company-grid">${cards || '<div class="empty-state">لا توجد شركات</div>'}</div></section>`); }
function filteredProducts() { const q = normalizeText(state.search); const route = state.view?.type || 'home'; const companyFilter = route === 'company' ? state.view.companyId : state.companyFilter; return state.products.filter((product) => { if (!product.visible || String(product.status || '').toLowerCase() === 'inactive') return false; if (companyFilter && String(product.company_id) !== String(companyFilter)) return false; if (!q) return true; return normalizeText(product.product_name).includes(q) || normalizeText(companyName(product.company_id)).includes(q) || normalizeText(product.product_id).includes(q); }); }
function productCardHtml(product) { const unit = currentUnitForProduct(product); const price = resolveProductPrice(product, unit); const qty = Number(state.productQtyPrefs?.[product.product_id] || 1); const units = availableUnits(product); const basePrice = baseUnitPrice(product, unit); const hasDiscount = Number(basePrice || 0) > 0 && Number(price || 0) > 0 && Math.abs(Number(price) - Number(basePrice)) > 0.001; const unitLabel = unit === 'pack' ? 'دستة' : 'كرتونة'; return `<article class="product-card" data-product-id="${escapeHtml(product.product_id)}"><button class="product-image-wrap" type="button" data-action="open-product" data-product-id="${escapeHtml(product.product_id)}"><img class="product-image" src="${escapeHtml(product.product_image || placeholderImage(product.product_name))}" alt="${escapeHtml(product.product_name)}" loading="lazy" /></button><div class="product-body"><div class="product-topline"><div class="product-title">${escapeHtml(product.product_name)}</div><div class="product-sub">${escapeHtml(companyName(product.company_id))}</div></div><div class="price-wrap"><span class="price-main">${price ? `${num(price)} ج.م` : '—'}</span>${hasDiscount ? `<span class="price-old">${num(basePrice)} ج.م</span>` : ''}</div><div class="unit-strip">${units.includes('carton') ? `<button class="mini-btn unit-chip ${unit === 'carton' ? 'is-current' : ''}" type="button" data-action="set-unit" data-product-id="${escapeHtml(product.product_id)}" data-unit="carton">كرتونة</button>` : ''}${units.includes('pack') ? `<button class="mini-btn unit-chip ${unit === 'pack' ? 'is-current' : ''}" type="button" data-action="set-unit" data-product-id="${escapeHtml(product.product_id)}" data-unit="pack">دستة</button>` : ''}</div><div class="qty-pick"><label class="qty-label">الكمية</label><input class="qty-input" type="number" min="1" inputmode="numeric" data-role="product-qty" data-product-id="${escapeHtml(product.product_id)}" value="${integer(qty)}" /></div><div class="card-actions"><button class="ghost-btn" type="button" data-action="open-product" data-product-id="${escapeHtml(product.product_id)}">تفاصيل</button><button class="primary-btn" type="button" data-action="add-product" data-product-id="${escapeHtml(product.product_id)}">إضافة ${escapeHtml(unitLabel)}</button></div></div></article>`; }
function renderProducts() { const rows = filteredProducts(); const route = state.view?.type || 'home'; const title = route === 'company' && state.view.companyId ? `منتجات ${companyName(state.view.companyId)}` : route === 'tiers' ? 'اختيارك التجاري' : route === 'deals' ? 'عروض مختارة' : 'المنتجات'; const helper = route === 'company' ? 'نتائج الشركة الحالية.' : 'البحث والتصفية يعملان مباشرة.'; const cards = rows.slice(0, route === 'home' ? 24 : 36).map(productCardHtml).join(''); setHtml(els.productsSurface, `<section class="section-card"><div class="section-head"><div><h2>${escapeHtml(title)}</h2><div class="helper-text">${escapeHtml(helper)} ${rows.length ? `النتائج: ${integer(rows.length)}` : ''}</div></div><button class="ghost-btn" type="button" data-action="open-tier-modal">الشريحة التجارية</button></div><div class="product-grid">${cards || '<div class="empty-state">لا توجد منتجات مطابقة</div>'}</div></section>`); }
function renderCart() { const totals = cartTotals(state.cart); const fullTotal = totals.total; const eligibleTotal = totals.eligible; const tier = getSelectedTierObject(); const minOrder = selectedTierMinimum(); const remaining = tier ? Math.max(0, minOrder - eligibleTotal) : null; const itemCount = state.cart.reduce((sum, item) => sum + Number(item.qty || 1), 0); const progress = tier && minOrder > 0 ? Math.max(0, Math.min(100, (eligibleTotal / minOrder) * 100)) : 0; const summaryHtml = `<div class="cart-summary"><div class="cart-summary-grid"><div class="cart-summary-card"><span class="cart-summary-label">عدد المنتجات</span><strong class="cart-summary-value mono">${integer(itemCount)}</strong></div><div class="cart-summary-card"><span class="cart-summary-label">قيمة الطلب</span><strong class="cart-summary-value mono">${num(fullTotal)} ج.م</strong></div><div class="cart-summary-card ${tier ? '' : 'is-muted'}"><span class="cart-summary-label">${tier ? 'حالة الشريحة' : 'الشريحة غير محددة'}</span><strong class="cart-summary-value mono">${tier ? tierDisplayLabel(tier) : '—'}</strong></div><div class="cart-summary-card"><span class="cart-summary-label">التقدم نحو الحد الأدنى</span><strong class="cart-summary-value mono">${tier ? `${integer(progress)}%` : '—'}</strong></div></div>${tier ? `<div class="cart-progress"><span style="width:${progress}%"></span></div>` : ''}${tier ? `<div class="helper-text">${remaining > 0 ? `متبقي ${num(remaining)} ج.م للوصول إلى الحد الأدنى.` : 'السلة مؤهلة بالكامل.'}</div>` : ''}</div>`; if (!state.cart.length) { setHtml(els.cartItems, `${summaryHtml}<div class="empty-state">السلة فارغة الآن</div>`); if (els.cartTotal) els.cartTotal.textContent = integer(fullTotal); syncCheckoutButton(); updateHeader(); return; } const html = state.cart.map((item) => { const badgeText = item.type === 'product' ? 'يحتسب ضمن الشريحة' : item.type === 'deal' ? 'سعر خاص' : 'عرض محدود'; return `<div class="cart-item"><img src="${escapeHtml(item.image || placeholderImage(item.title))}" alt="${escapeHtml(item.title)}" loading="lazy" /><div><div class="cart-topline"><h4 class="cart-title">${escapeHtml(item.title)}</h4><span class="cart-item-badge ${item.type === 'product' ? 'badge-product' : item.type === 'deal' ? 'badge-deal' : 'badge-flash'}">${escapeHtml(badgeText)}</span></div><div class="cart-meta">${escapeHtml(item.company || '')}</div><div class="cart-price">${escapeHtml(item.unitLabel || item.unit || '')} · ${num(item.price)} ج.م</div>${item.unit === 'single' ? `<div class="qty-row single-item-row"><button class="ghost-btn" data-action="remove-item" data-key="${escapeHtml(item.key)}" type="button">إزالة</button></div>` : `<div class="qty-row"><button data-action="qty-down" data-key="${escapeHtml(item.key)}" type="button">-</button><input data-role="cart-qty" data-key="${escapeHtml(item.key)}" type="number" min="1" value="${integer(item.qty || 1)}" inputmode="numeric" /><button data-action="qty-up" data-key="${escapeHtml(item.key)}" type="button">+</button><button class="ghost-btn" data-action="remove-item" data-key="${escapeHtml(item.key)}" type="button">حذف</button></div>`}</div></div>`; }).join(''); setHtml(els.cartItems, `${summaryHtml}${html}`); if (els.cartTotal) els.cartTotal.textContent = integer(fullTotal); syncCheckoutButton(); updateHeader(); }
function renderTierModal() { const tier = getSelectedTierObject(); const cards = state.tiers.length ? state.tiers.map((item) => { const current = tier && String(item.tier_name) === String(tier.tier_name); return `<article class="tier-card ${current ? 'is-current' : ''}"><div class="tier-card-head"><strong>${escapeHtml(tierDisplayLabel(item))}</strong><span class="badge badge-tier">${current ? 'الحالية' : `خصم ${num(item.discount_percent || 0)}%`}</span></div><div class="tier-min">الحد الأدنى ${num(item.min_order || 0)} ج.م</div><div class="helper-text">${escapeHtml(item.description || 'شريحة تسعير تجارية')}</div><button class="primary-btn" data-action="select-tier" data-tier-name="${escapeHtml(item.tier_name)}" type="button">${current ? 'الحالية' : 'اختيار'}</button></article>`; }).join('') : '<div class="empty-state">لا توجد شرائح معرفة</div>'; setHtml(els.tierModalBody, `<div class="tier-modal-copy"><div class="helper-text">اختر الشريحة المناسبة. عند أول إضافة ستُثبت الشريحة ثم تُضاف العملية تلقائيًا.</div></div><div class="tier-grid tier-grid-modal">${cards}</div><div class="tier-modal-foot"><button class="ghost-btn" data-action="navigate" data-hash="#tiers" type="button">عرض الصفحة الكاملة</button></div>`); }
function renderProductModal(product) { const unit = currentUnitForProduct(product); const inCart = Boolean(findCartItem(currentCartKey({ type: 'product', id: product.product_id, unit }))); const unitText = unit === 'pack' ? 'دستة' : 'كرتونة'; const priceText = displayPriceText(product, unit); setHtml(els.productModalBody, `<div class="modal-hero"><img src="${escapeHtml(product.product_image || placeholderImage(product.product_name))}" alt="${escapeHtml(product.product_name)}" class="modal-image" /><div class="modal-meta"><div class="badge-row"><span class="badge">${escapeHtml(companyName(product.company_id))}</span><span class="badge">${escapeHtml(unitText)}</span></div><div class="price-main">${escapeHtml(priceText)}</div><p class="helper-text">${escapeHtml(product.allow_discount === false ? 'غير قابل للخصم' : 'قابل للتسعير حسب الشريحة')}</p></div></div><div class="helper-text">${escapeHtml(product.description || '')}</div>`); if (els.productModalTitle) els.productModalTitle.textContent = product.product_name; if (els.productModalAction) { els.productModalAction.textContent = inCart ? 'إزالة من السلة' : 'إضافة للسلة'; els.productModalAction.dataset.action = inCart ? 'remove-product-from-modal' : 'add-product-from-modal'; els.productModalAction.dataset.productId = product.product_id; els.productModalAction.dataset.unit = unit; } openModal(els.productModal); }
function openModal(el) { setOverlayState(el, true); }
