function renderMyDataModal() { const session = state.session; const invoices = state.invoices || []; const body = session ? `<div class="profile-grid"><div class="account-summary-card"><span class="account-summary-label">الاسم</span><strong>${escapeHtml(session.name || session.username || session.phone || 'مستخدم')}</strong></div><div class="account-summary-card"><span class="account-summary-label">النوع</span><strong>${escapeHtml(session.userType || 'customer')}</strong></div><div class="account-summary-card"><span class="account-summary-label">الهاتف</span><strong>${escapeHtml(session.phone || '—')}</strong></div></div><div class="section-card"><h3>آخر الفواتير</h3><div class="invoice-list">${invoices.length ? invoices.slice(0, 6).map((invoice) => `<article class="invoice-card"><div class="invoice-top"><strong>#${escapeHtml(invoice.order_number || invoice.id || '')}</strong><span class="badge">${escapeHtml(invoice.status || '')}</span></div><div class="invoice-meta">${escapeHtml(formatDateTime(invoice.created_at))}</div></article>`).join('') : '<div class="empty-state">لا توجد فواتير</div>'}</div></div>` : '<div class="empty-state">لا توجد جلسة حالية</div>'; setHtml(els.myDataContent, body); }
function setTierByName(tierName) { const tier = state.tiers.find((item) => String(item.tier_name) === String(tierName)); if (!tier) return; state.selectedTier = tier; persistTier(); syncCartPricesFromCurrentState(); resetCheckoutStage(); renderAll(); toast(`تم اختيار ${tierDisplayLabel(tier)}`, 'success'); if (state.pendingTierAction) { const pending = state.pendingTierAction; state.pendingTierAction = null; addProductToCartById(pending.productId, pending.unit, pending.qty, true); } closeModal(els.tierModal); }
function addProductToCartById(productId, unit = null, qty = null, force = false) { const product = state.productMap.get(String(productId)); if (!product) return; if (!getSelectedTierObject() && !force) { state.pendingTierAction = { productId, unit: unit || currentUnitForProduct(product), qty: qty || Number(state.productQtyPrefs?.[product.product_id] || 1) }; openTierModal(); toast('اختر الشريحة أولاً لإكمال الإضافة', 'warning'); return; } const nextUnit = unit || currentUnitForProduct(product); const nextQty = Math.max(1, Math.floor(Number(qty || state.productQtyPrefs?.[product.product_id] || 1))); const key = currentCartKey({ type: 'product', id: product.product_id, unit: nextUnit }); const price = resolveProductPrice(product, nextUnit); const unitLabel = nextUnit === 'pack' ? 'دستة' : 'كرتونة'; const existing = findCartItem(key); if (existing) existing.qty += nextQty; else state.cart.push({ key, type: 'product', id: product.product_id, title: product.product_name, company: companyName(product.company_id), image: product.product_image || placeholderImage(product.product_name), unit: nextUnit, unitLabel, qty: nextQty, price }); persistCart(); syncCartPricesFromCurrentState(); resetCheckoutStage(); renderAll(); toast(`تمت إضافة ${product.product_name}`, 'success'); }
function removeCartItem(key) { state.cart = state.cart.filter((item) => item.key !== key); persistCart(); resetCheckoutStage(); renderAll(); }
function setCartQty(key, qty) { const item = state.cart.find((row) => row.key === key); if (!item) return; item.qty = Math.max(1, Number(qty || 1)); persistCart(); resetCheckoutStage(); renderAll(); }
function toggleCartQty(key, delta) { const item = state.cart.find((row) => row.key === key); if (!item) return; item.qty = Math.max(1, Number(item.qty || 1) + delta); persistCart(); resetCheckoutStage(); renderAll(); }
function toggleUnitPreference(productId, unit) { state.unitPrefs[productId] = unit; writeJSON(STORAGE.unitPrefs, state.unitPrefs); renderAll(); }
function addDealToCartById(id) { const item = state.dailyDeals.find((row) => String(row.id) === String(id)); if (!item) return; const key = currentCartKey({ type: 'deal', id: String(item.id), unit: 'single' }); const existing = findCartItem(key); if (existing) { removeCartItem(key); toast('تمت إزالة العرض من السلة', 'info'); return; } state.cart.push({ key, type: 'deal', id: String(item.id), title: item.title, company: item.company_name || '', image: item.image || placeholderImage(item.title), unit: 'single', unitLabel: 'عرض خاص', qty: 1, price: Number(item.price || 0) }); persistCart(); resetCheckoutStage(); renderAll(); toast('تمت إضافة العرض', 'success'); }
function addFlashToCartById(id) { const item = state.flashOffers.find((row) => String(row.id) === String(id)); if (!item) return; const key = currentCartKey({ type: 'flash', id: String(item.id), unit: 'single' }); const existing = findCartItem(key); if (existing) { removeCartItem(key); toast('تمت إزالة العرض من السلة', 'info'); return; } state.cart.push({ key, type: 'flash', id: String(item.id), title: item.title, company: item.company_name || '', image: item.image || placeholderImage(item.title), unit: 'single', unitLabel: 'عرض الساعة', qty: 1, price: Number(item.price || 0) }); persistCart(); resetCheckoutStage(); renderAll(); toast('تمت إضافة عرض الساعة', 'success'); }
async function validateCartAgainstDatabase() { if (!state.cart.length) { toast('السلة فارغة', 'warning'); return { ok: false, message: 'السلة فارغة' }; } const productItems = state.cart.filter((item) => item.type === 'product'); if (!productItems.length) { toast('السلة تحتوي على عروض فقط', 'info'); return { ok: true, message: 'عروض فقط' }; } const ids = [...new Set(productItems.map((item) => String(item.id)))]; try { const [freshProducts, freshTier] = await Promise.all([ ids.length ? apiGet('v_products', { select: 'product_id,product_name,company_id,has_carton,has_pack,carton_price,pack_price,allow_discount,discount_pack,discount_carton', product_id: `in.(${ids.join(',')})` }).catch(() => []) : Promise.resolve([]), getSelectedTierObject()?.tier_name ? apiGet('tiers', { select: 'tier_name,min_order,visible_label,discount_percent', tier_name: `eq.${getSelectedTierObject().tier_name}`, limit: '1' }).catch(() => []) : Promise.resolve([]) ]); const productsMap = new Map((freshProducts || []).map((row) => [String(row.product_id), row])); const tierRow = Array.isArray(freshTier) ? freshTier[0] : freshTier?.[0]; for (const item of productItems) { const product = productsMap.get(String(item.id)); if (!product) return { ok: false, message: `المنتج ${item.title} غير موجود الآن` }; const base = item.unit === 'pack' ? Number(product.pack_price || 0) : Number(product.carton_price || 0); const discount = tierRow && product.allow_discount !== false && !(String(item.unit || '') === 'pack' && product.discount_pack === false) && !(String(item.unit || '') === 'carton' && product.discount_carton === false) ? Number(tierRow.discount_percent || 0) : 0; const livePrice = discount > 0 && base > 0 ? Number((base * (1 - discount / 100)).toFixed(2)) : base; if (Math.abs(Number(item.price || 0) - livePrice) > 0.0001) return { ok: false, message: `سعر ${item.title} تغيّر. أعد إضافة المنتج من جديد` }; } const minOrder = Number(tierRow?.min_order || getSelectedTierObject()?.min_order || 0); const eligible = eligibleTierTotal(state.cart); if (minOrder > 0 && eligible < minOrder) return { ok: false, message: `السلة لم تصل إلى الحد الأدنى (${num(minOrder)} ج.م)` }; return { ok: true, message: 'السلة صحيحة' }; } catch (error) { console.error(error); return { ok: false, message: 'تعذر التحقق من السلة الآن' }; } }
async function checkoutCart() { const result = await validateCartAgainstDatabase(); if (result.ok) { state.checkoutStage = 'submit'; syncCheckoutButton(); toast('السلة صحيحة وجاهزة', 'success'); } else { state.checkoutStage = 'validate'; syncCheckoutButton(); toast(result.message, 'error'); } }
function clearCompanyFilter() { state.companyFilter = null; renderAll(); }
function openCompany(companyId) { state.companyFilter = String(companyId); navigate(`#company/${encodeURIComponent(String(companyId))}`); }
function openDealModal(id) { const item = state.dailyDeals.find((row) => String(row.id) === String(id)); if (!item) return; state.activeDeal = item; state.activeProduct = null; if (els.productModalTitle) els.productModalTitle.textContent = item.title; if (els.productModalBody) setHtml(els.productModalBody, `<div class="modal-hero"><img src="${escapeHtml(item.image || placeholderImage(item.title))}" alt="${escapeHtml(item.title)}" class="modal-image" /><div class="modal-meta"><div class="badge-row"><span class="badge">عرض يومي</span>${item.discount_percent ? `<span class="badge">خصم ${num(item.discount_percent)}%</span>` : ''}</div><div class="price-main">${item.price ? `${num(item.price)} ج.م` : 'سعر خاص'}</div><p class="helper-text">${escapeHtml(item.description || '')}</p></div></div>`); if (els.productModalAction) { els.productModalAction.textContent = 'إضافة للسلة'; els.productModalAction.dataset.action = 'toggle-deal'; els.productModalAction.dataset.id = String(item.id); els.productModalAction.removeAttribute('data-product-id'); } openModal(els.productModal); }
