function wireSearchSurface() { if (els.headerSearchInput) { els.headerSearchInput.addEventListener('input', (event) => { state.search = String(event.target.value || ''); renderAll(); }); els.headerSearchInput.addEventListener('keydown', (event) => { if (event.key === 'Escape' && els.headerSearchInput.value) { state.search = ''; renderAll(); } }); } if (els.headerClearSearchBtn) els.headerClearSearchBtn.addEventListener('click', () => { state.search = ''; renderAll(); }); }
function bindGlobalEvents() { if (globalEventsBound) return; globalEventsBound = true; wireSearchSurface(); if (els.menuBtn) els.menuBtn.addEventListener('click', () => openDrawer(els.navDrawer)); if (els.cartBtn) els.cartBtn.addEventListener('click', openCartDrawer); if (els.userBtn) els.userBtn.addEventListener('click', () => { if (state.session) openMyDataModal(); else openLoginModal(); }); if (els.checkoutBtn) els.checkoutBtn.addEventListener('click', checkoutCart); if (els.saveCartBtn) els.saveCartBtn.addEventListener('click', () => { persistCart(); toast('تم حفظ السلة', 'success'); }); document.addEventListener('click', async (event) => { const actionEl = event.target.closest('[data-action]'); const closeEl = event.target.closest('[data-close]'); if (closeEl) { closeModal(document.getElementById(closeEl.dataset.close)); closeDrawer(document.getElementById(closeEl.dataset.close)); return; } if (!actionEl) return; event.preventDefault(); const action = actionEl.dataset.action; if (action === 'navigate') return navigate(actionEl.dataset.hash || '#home'); if (action === 'open-tier-modal') return openTierModal(); if (action === 'select-tier') return setTierByName(actionEl.dataset.tierName); if (action === 'set-unit') return toggleUnitPreference(actionEl.dataset.productId, actionEl.dataset.unit); if (action === 'add-product') return addProductToCartById(actionEl.dataset.productId); if (action === 'open-product') return openProductById(actionEl.dataset.productId); if (action === 'remove-product-from-modal') { const productId = actionEl.dataset.productId; const unit = actionEl.dataset.unit || currentUnitForProduct(state.productMap.get(String(productId))); return removeCartItem(currentCartKey({ type: 'product', id: String(productId), unit })), closeModal(els.productModal); } if (action === 'add-product-from-modal') return addProductToCartById(actionEl.dataset.productId, actionEl.dataset.unit), closeModal(els.productModal); if (action === 'qty-up') return toggleCartQty(actionEl.dataset.key, 1); if (action === 'qty-down') return toggleCartQty(actionEl.dataset.key, -1); if (action === 'remove-item') return removeCartItem(actionEl.dataset.key); if (action === 'open-company') return openCompany(actionEl.dataset.companyId); if (action === 'clear-company-filter') return clearCompanyFilter(); if (action === 'open-deal') return openDealModal(actionEl.dataset.id); if (action === 'toggle-deal') return addDealToCartById(actionEl.dataset.id), closeModal(els.productModal); if (action === 'toggle-flash') return addFlashToCartById(actionEl.dataset.id), closeModal(els.productModal); if (action === 'open-cart') return openCartDrawer(); if (action === 'open-login') return openLoginModal(); if (action === 'open-register') return openAddCustomerModal(); if (action === 'save-customer') return saveCustomerFromForm(); if (action === 'submit-login') return attemptLogin(); if (action === 'home-cta') return navigate(actionEl.dataset.hash || '#home'); }); document.addEventListener('input', (event) => { const qtyInput = event.target.closest('[data-role="product-qty"]'); if (qtyInput) { const productId = qtyInput.dataset.productId; state.productQtyPrefs[productId] = Math.max(1, Math.floor(Number(qtyInput.value || 1))); writeJSON(STORAGE.productQtyPrefs, state.productQtyPrefs); return; } const cartQtyInput = event.target.closest('[data-role="cart-qty"]'); if (cartQtyInput) setCartQty(cartQtyInput.dataset.key, cartQtyInput.value); }); document.addEventListener('keydown', (event) => { if (event.key === 'Escape') { closeOverlay(els.productModal); closeOverlay(els.tierModal); closeOverlay(els.loginModal); closeOverlay(els.myDataModal); closeOverlay(els.addCustomerModal); closeDrawer(els.navDrawer); } }); window.addEventListener('hashchange', handleRoute); }
async function apiGet(table, params = {}) { const url = new URL(`${CONFIG.baseUrl}/${table}`); for (const [key, value] of Object.entries(params || {})) { if (value === undefined || value === null || value === '') continue; url.searchParams.set(key, value); } const response = await fetch(url, { headers: { apikey: CONFIG.apiKey, Authorization: `Bearer ${CONFIG.apiKey}`, Accept: 'application/json', 'Content-Type': 'application/json' } }); if (!response.ok) throw new Error(`Failed to load ${table}: ${response.status}`); return response.json(); }
async function safeGet(table, params = {}, fallback = []) { try { const data = await apiGet(table, params); return Array.isArray(data) ? data : fallback; } catch { return fallback; } }
function buildTierPriceIndex(rows = [], unit = 'carton') { const map = new Map(); for (const row of rows) { const tierName = String(row.tier_name || '').trim(); const productId = String(row.product_id || '').trim(); const price = Number(row.price || 0); if (!tierName || !productId || !Number.isFinite(price) || price <= 0) continue; map.set(`${tierName}::${productId}`, price); } state.tierPrices[unit] = map; }
function mergeRawProducts(rawProducts, cartonRows, packRows) { const cartonMap = new Map(); const packMap = new Map(); for (const row of cartonRows) { if (!row.product_id) continue; if (!cartonMap.has(String(row.product_id))) cartonMap.set(String(row.product_id), Number(row.price || 0)); } for (const row of packRows) { if (!row.product_id) continue; if (!packMap.has(String(row.product_id))) packMap.set(String(row.product_id), Number(row.price || 0)); } return rawProducts.map((row) => normalizeProductRow(row, row.carton_price ?? cartonMap.get(String(row.product_id)) ?? 0, row.pack_price ?? packMap.get(String(row.product_id)) ?? 0)); }
async function loadData() { const [companies, viewProducts, rawProducts, dailyDeals, flashOffers, tiers, settings, topProducts, topCompanies, cartonRows, packRows] = await Promise.all([ safeGet('companies', { select: 'company_id,company_name,company_logo,visible,allow_discount', visible: 'eq.true', order: 'company_id.asc' }, []), safeGet('v_products', { select: 'product_id,product_name,product_image,company_id,has_carton,has_pack,carton_price,pack_price,allow_discount,discount_pack,discount_carton,visible,status', order: 'product_name.asc' }, []), safeGet('products', { select: 'product_id,product_name,company_id,product_image,status,visible,has_carton,has_pack,discount_carton,discount_pack', order: 'product_name.asc' }, []), safeGet('daily_deals', { select: '*', order: 'id.desc' }, []), safeGet('flash_offers', { select: '*', order: 'start_time.desc' }, []), safeGet('tiers', { select: 'tier_name,visible_label,min_order,discount_percent,description', order: 'min_order.asc' }, []), safeGet('app_settings', { select: 'key,value,updated_at', order: 'updated_at.desc' }, []), safeGet('v_top_products', { select: '*' }, []), safeGet('v_top_companies', { select: '*' }, []), safeGet('prices_carton', { select: 'product_id,tier_name,price,visible', visible: 'eq.true', order: 'product_id.asc,tier_name.asc' }, []), safeGet('prices_pack', { select: 'product_id,tier_name,price,visible', visible: 'eq.true', order: 'product_id.asc,tier_name.asc' }, []) ]); const normalizedViewProducts = (viewProducts || []).map((row) => normalizeProductRow(row)); const normalizedRawProducts = mergeRawProducts(rawProducts || [], cartonRows || [], packRows || []); const productRows = normalizedViewProducts.length ? normalizedViewProducts : normalizedRawProducts; state.companies = sortCompanies(Array.isArray(companies) ? companies : []); state.products = sortProducts(productRows || []); state.dailyDeals = normalizeDeals(Array.isArray(dailyDeals) ? dailyDeals : []); state.flashOffers = normalizeFlashOffers(Array.isArray(flashOffers) ? flashOffers : []); state.tiers = Array.isArray(tiers) ? tiers : []; state.settings = Array.isArray(settings) ? settings : []; state.settingMap = new Map(state.settings.map((row) => [row.key, row.value])); state.companyMap = new Map(state.companies.map((company) => [String(company.company_id), company])); state.productMap = new Map(state.products.map((product) => [String(product.product_id), product])); state.topProducts = Array.isArray(topProducts) && topProducts.length ? topProducts : state.products.slice(0, 12).map((product) => ({ product_id: product.product_id })); state.topCompanies = Array.isArray(topCompanies) && topCompanies.length ? topCompanies : state.companies.slice(0, 12).map((company) => ({ company_id: company.company_id })); buildTierPriceIndex(cartonRows || [], 'carton'); buildTierPriceIndex(packRows || [], 'pack'); if (state.selectedTier) { const key = typeof state.selectedTier === 'string' ? state.selectedTier : state.selectedTier.tier_name; const matched = state.tiers.find((tier) => String(tier.tier_name) === String(key)); state.selectedTier = matched || state.selectedTier; persistTier(); } syncCartPricesFromCurrentState(); renderAll(); }
function renderAll() { state.view = parseHash(); updateHeader(); updateFlashHeader(); const type = state.view.type; const routeCompany = type === 'company' ? state.view.companyId : null; state.companyFilter = routeCompany || state.companyFilter; if (els.mobileHeaderShell) els.mobileHeaderShell.classList.toggle('hidden', type === 'register'); if (els.bottomNav) els.bottomNav.classList.toggle('hidden', type === 'register'); if (els.searchBar) els.searchBar.classList.toggle('hidden', type === 'register'); const showCartDrawer = type === 'cart' || state.pendingOpenCart; const showAccount = type === 'account'; state.pendingOpenCart = false; renderHomePage(); if (type === 'tiers') renderTierPage(); else if (type === 'deals') renderDealsPage(); else if (type === 'flash') renderFlashPage(); else if (type === 'account') renderAccountPage(); else if (type === 'company') renderCompanyPage(); if (type === 'cart') openCartDrawer(); else if (!showCartDrawer) closeDrawer(els.cartDrawer); if (type === 'account') { if (state.session) openMyDataModal(); else openLoginModal(); } else if (!showAccount) { closeOverlay(els.loginModal); closeOverlay(els.myDataModal); } if (type === 'register') openAddCustomerModal(); else closeOverlay(els.addCustomerModal); if (type === 'flash') { const flash = flashState(); if (flash.offer) openFlashModal(); } }
async function attemptLogin() { const identifier = String(els.loginIdentifier?.value || '').trim(); const password = String(els.loginPassword?.value || '').trim(); if (!identifier || !password) { toast('أدخل رقم الهاتف أو اسم المستخدم وكلمة المرور', 'warning'); return; } for (const table of ['customers', 'users']) { try { const byPhone = await safeGet(table, { select: 'id,name,phone,username,password,user_type', phone: `eq.${identifier}`, limit: '10' }, []); const byUser = await safeGet(table, { select: 'id,name,phone,username,password,user_type', username: `eq.${identifier}`, limit: '10' }, []); const rows = [...byPhone, ...byUser]; const match = rows.find((row) => String(row.password || row.pin || '') === password || !row.password); if (match) { state.session = { id: String(match.id), name: match.name || match.username || match.phone || identifier, phone: match.phone || identifier, username: match.username || identifier, userType: match.user_type || (table === 'customers' ? 'customer' : 'user') }; persistSession(); closeModal(els.loginModal); renderAll(); toast('تم تسجيل الدخول', 'success'); return; } } catch {} } state.session = { id: `local-${Date.now()}`, name: identifier, phone: identifier, username: identifier, userType: 'customer' }; persistSession(); closeModal(els.loginModal); renderAll(); toast('تم إنشاء جلسة محلية', 'success'); }
async function saveCustomerFromForm() { const name = String(els.custName?.value || '').trim(); const phone = String(els.custPhone?.value || '').trim(); const address = String(els.custAddress?.value || '').trim(); if (!name || !phone) { toast('أدخل اسم العميل ورقم الهاتف', 'warning'); return; } const customer = { id: `local-${Date.now()}`, name, phone, address }; state.customers = [customer, ...(state.customers || [])]; state.selectedCustomer = customer; persistSelectedCustomer(); closeModal(els.addCustomerModal); renderAll(); toast('تم حفظ العميل محليًا', 'success'); }
async function loadInvoices() { if (!state.session) { state.invoices = []; state.invoicesLoaded = true; return; } const filterKey = state.session.userType === 'customer' ? 'customer_id' : 'user_id'; state.invoices = await safeGet('orders', { select: 'id,order_number,created_at,total_amount,status,user_type,customer_id,user_id,updated_at', [filterKey]: `eq.${state.session.id}`, order: 'created_at.desc' }, []); state.invoicesLoaded = true; }
async function bootFlashTicker() { clearInterval(state.timers.flash); state.timers.flash = setInterval(() => { if (!document.hidden) { updateFlashHeader(); if (state.view?.type === 'home' || state.view?.type === 'flash' || state.view?.type === 'deals') renderHero(); } }, 1000); }
function handleRoute() { const route = parseHash(); state.view = route; if (route.type === 'cart') state.pendingOpenCart = true; if (route.type === 'company' && route.companyId) state.companyFilter = route.companyId; renderAll(); }
export async function startApplication() { bindGlobalEvents(); await loadData(); await loadInvoices(); await bootFlashTicker(); handleRoute(); updateHeader(); renderAll(); }
